# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int purchaseQuantity)
{
    using (var dbContext = new EventBookingContext())
    {
        var eventEntity = await dbContext.Events
            .Where(e => e.EventId == eventId)
            .FirstOrDefaultAsync();

        if (eventEntity == null)
            throw new Exception("Event not found.");

        if (purchaseQuantity <= 0)
            throw new ArgumentException("Purchase quantity must be greater than zero.");

        bool success = false;
        while (!success)
        {
            try
            {
                if (eventEntity.AvailableSeats >= purchaseQuantity)
                {
                    eventEntity.AvailableSeats -= purchaseQuantity;
                    dbContext.Entry(eventEntity).State = EntityState.Modified;
                    
                    await dbContext.SaveChangesAsync();
                    success = true;
                }
                else
                {
                    throw new Exception("Not enough seats available.");
                }
            }
            catch (DbUpdateConcurrencyException)
            {
                // Refresh the entity and try again
                await dbContext.Entry(eventEntity).ReloadAsync();
            }
        }

        return success;
    }
}